"""Fetch and print a simple weather summary for San Francisco using wttr.in."""

from __future__ import annotations

import json
import sys
import urllib.error
import urllib.parse
import urllib.request


CITY = "San Francisco"
URL = f"https://wttr.in/{urllib.parse.quote(CITY)}?format=j1"


def fetch_weather(url: str) -> dict:
    request = urllib.request.Request(
        url,
        headers={
            "User-Agent": "weather-summary-script/1.0",
            "Accept": "application/json",
        },
    )
    with urllib.request.urlopen(request, timeout=10) as response:
        return json.load(response)


def build_summary(data: dict) -> str:
    current = data["current_condition"][0]
    description = current["weatherDesc"][0]["value"]
    temperature_c = current["temp_C"]
    feels_like_c = current["FeelsLikeC"]
    humidity = current["humidity"]
    wind_kmph = current["windspeedKmph"]

    return (
        f"Weather for {CITY}: {description}. "
        f"Temperature: {temperature_c}°C, feels like {feels_like_c}°C. "
        f"Humidity: {humidity}%. Wind: {wind_kmph} km/h."
    )


def main() -> int:
    try:
        data = fetch_weather(URL)
        print(build_summary(data))
        return 0
    except urllib.error.URLError as exc:
        print(f"Failed to fetch weather data: {exc}", file=sys.stderr)
    except (KeyError, IndexError, ValueError, json.JSONDecodeError) as exc:
        print(f"Failed to parse weather data: {exc}", file=sys.stderr)
    return 1


if __name__ == "__main__":
    raise SystemExit(main())
